PowerPannelByTemp_calc.fnCalc:
/**
 * ESTIME LA PUISSANCE PRODUITE PAR 1M2 DE PANNEAUX SOLAIRES
 * --------------------------------------------------------
 * Cette fonction modélise le comportement d'un panneau fixe incliné
 * en utilisant les données d'une station météo Davis Vantage Pro2.
 * * @param {Object} data - Données de la station (incluant l'irradiation et la température)
 * @param {number} lon - Longitude du site (définie par l'utilisateur)
 * @param {number} lat - Latitude du site (définie par l'utilisateur)
 * @param {number} alt - Altitude du site (définie par l'utilisateur)
 * @returns {string} - Puissance estimée en Watts (formatée à 2 décimales)
 */
(data, lon=%longitude%, lat=%latitude% , alt=%altitude%) => {

    // --- 1. CONFIGURATION DU MATÉRIEL ---
    const PANEL_AZIMUTH = 157.5 * (Math.PI / 180); // Orientation Sud-Sud-Est (convertie en radians)
    const PANEL_TILT = 30 * (Math.PI / 180);       // Inclinaison de 30° (optimale pour les latitudes moyennes)
    const efficiency = 0.18;                       // Rendement nominal du panneau (18%)
    const tempCoeff = -0.004;                      // Perte de 0.4% par degré au-dessus de 25°C
    const installDate = "2010-01-01";              // Date de mise en service pour le calcul d'usure
    const annualDegradation = 0.005;               // Perte de rendement annuelle (0.5%)
    const lastCleaningDate = "2024-04-15";         // Date du dernier entretien
    const dailySoilingRate = 0.0001;               // Accumulation quotidienne de poussière (0.01%/jour)

    // SEUIL CRITIQUE : En dessous de 30 W/m2 reçus sur le panneau, l'onduleur ne démarre pas
    const MIN_IRRADIANCE_THRESHOLD = 30.0; 

    // --- 2. RÉCUPÉRATION DES DONNÉES CAPTEURS ---
    const G_horiz = data['irradiance:solar'];        // Irradiation globale horizontale (W/m2)
    const T_ext = data['temperature:outTemp'] - 273.15; // Conversion Kelvin vers Celsius
    const now = new Date(data.d);                    // Horodatage précis de la mesure

    // --- 3. CALCUL DE LA POSITION DU SOLEIL ---
    // Utilisation de SunCalc pour obtenir l'angle exact du soleil au moment de la mesure
    const sunPos = SunCalc.getPosition(now, lat, lon);
    const sunAlt = sunPos.altitude;    // Hauteur du soleil au-dessus de l'horizon (radians)
    const sunAzimuth = sunPos.azimuth; // Direction du soleil (radians)

    // --- 4. GESTION DES LIMITES (NUIT / HORIZON) ---
    // Si le soleil est sous l'horizon ou trop bas (2°), l'épaisseur atmosphérique bloque tout rayonnement utile
    if (sunAlt < (2 * Math.PI / 180)) return 0;

    // --- 5. CALCUL DE L'ANGLE D'INCIDENCE (AOI) ---
    // On calcule l'angle entre les rayons du soleil et la normale (perpendiculaire) du panneau.
    // Formule trigonométrique de projection :
    const cosAOI = Math.cos(sunAlt) * Math.sin(PANEL_TILT) * Math.cos(sunAzimuth - PANEL_AZIMUTH) 
                 + Math.sin(sunAlt) * Math.cos(PANEL_TILT);

    // Si cosAOI <= 0, le soleil est derrière le panneau (ombre propre)
    if (cosAOI <= 0) return 0;

    // --- 6. PROJECTION DE L'IRRADIATION SUR LE PLAN INCLINÉ ---
    // On convertit l'irradiation "à plat" du pyranomètre en irradiation "reçue" par le panneau incliné.
    let G_inc = G_horiz * (cosAOI / Math.sin(sunAlt));

    // Limitation de sécurité : l'irradiation projetée ne peut pas dépasser physiquement un certain ratio
    // Cela évite les pics mathématiques infinis au lever/coucher du soleil (quand sin(sunAlt) tend vers 0)
    G_inc = Math.min(G_inc, G_horiz * 1.5); 

    // --- 7. APPLICATION DU SEUIL D'IRRADIATION ---
    // Si l'énergie reçue est trop faible pour exciter les cellules ou réveiller l'onduleur
    if (G_inc < MIN_IRRADIANCE_THRESHOLD) return 0;

    // --- 8. CALCUL DES FACTEURS DE PERTES ENVIRONNEMENTALES ---

    // A. Salissure (Soiling) : Dépend du temps écoulé depuis le dernier nettoyage
    const daysSinceCleaning = Math.max(0, (now - new Date(lastCleaningDate)) / (1000 * 3600 * 24));
    const soilingFactor = Math.max(0.80, 1 - (daysSinceCleaning * dailySoilingRate)); // Plafonné à 20% de perte

    // B. Vieillissement (Age) : Dégradation chimique lente du silicium au fil des ans
    const ageInYears = Math.max(0, (now - new Date(installDate)) / (1000 * 60 * 60 * 24 * 365.25));
    const ageFactor = Math.max(0.7, 1 - (ageInYears * annualDegradation)); // Plafonné à 30% de perte (durée de vie standard)

    // --- 9. CORRECTION THERMIQUE ---
    // Les panneaux perdent de l'efficacité en chauffant.
    // On estime la température de la cellule (T_cell) via le modèle NOCT (Nominal Operating Cell Temperature)
    const T_cell = T_ext + (G_inc * (25 / 800)); // Le panneau est environ 25°C plus chaud que l'air à 800W/m2
    const thermalCorrection = 1 + tempCoeff * (T_cell - 25); // Correction basée sur l'écart à la température de référence (25°C)

    // --- 10. CALCUL FINAL DE LA PUISSANCE ---
    // Puissance = Énergie incidente * Surface (1m2) * Rendement * Corrections
    let power = G_inc * efficiency * thermalCorrection * ageFactor * soilingFactor;

    // Retourne le résultat final (Watts par m2)
    return Math.round(Math.max(0, power) * 100) / 100;
}

PerfecPannel_calc.fnCalc:
/**
 * Estime la puissance produite en tenant compte de l'usure temporelle
 * @param {number} G_horiz - Irradiation pyranomètre (W/m2)
 * @param {number} T_ext - Température extérieure (°C)
 * @param {number} tilt - Inclinaison (degrés)
 * @param {number} efficiency - Rendement nominal (ex: 0.17)
 * @param {number} tempCoeff - Coeff de température (ex: -0.004)
 * @param {string} installDate - Date d'installation (Format "YYYY-MM-DD")
 * @param {number} annualDegradation - Perte annuelle (défaut 0.005 pour 0.5%)
 * @returns {Object}
 * Calcul de la puissance produite avec correction d'angle d'incidence (SunCalc)
 */
(data, lon=%longitude%, lat=%latitude% , alt=%altitude%) => {
    // Import ou référence à SunCalc (assumé disponible dans l'environnement)
    // Azimut panneau : Sud = 180°, SSE = 157.5°
    const PANEL_AZIMUTH = 157.5 * (Math.PI / 180); 
    const PANEL_TILT = 30 * (Math.PI / 180);

    const G_horiz = data['irradiance:solar'];
    const T_ext = data['temperature:outTemp'] - 273.15; // Kelvin to Celsius

    const efficiency = 0.18;
    const tempCoeff = -0.000;
    const installDate = "2010-01-01";
    const annualDegradation = 0.000;

    // 1. Position du soleil via SunCalc
    const now = new Date(data.d);
    const sunPos = SunCalc.getPosition(now, lat, lon);
    const sunAzimuth = sunPos.azimuth; // Radian (Sud = 0, diverge de SunCalc standard selon version)
    // Note: Dans suncalc3, l'azimut 0 est souvent le Sud ou le Nord selon la config.
    // Ajustons pour que le calcul d'angle d'incidence soit robuste :
    const sunAlt = sunPos.altitude;

    // 2. Limite tangentielle et nuit
    // Si le soleil est sous l'horizon (ou très proche), prod = 0
    if (sunAlt < (2 * Math.PI / 180)) return 0;

    // 3. Calcul de l'Angle d'Incidence (AOI)
    // Formule : cos(AOI) = cos(alpha)*sin(beta)*cos(psi_s - psi_p) + sin(alpha)*cos(beta)
    // alpha = altitude soleil, beta = inclinaison panneau, psi = azimut
    const cosAOI = Math.cos(sunAlt) * Math.sin(PANEL_TILT) * Math.cos(sunAzimuth - PANEL_AZIMUTH) 
                 + Math.sin(sunAlt) * Math.cos(PANEL_TILT);

    // Si cosAOI <= 0, le soleil est derrière le panneau
    if (cosAOI <= 0) return 0;

    // 4. Estimation de l'irradiation sur le plan incliné (G_inc)
    // On utilise le ratio de projection : G_inc = G_horiz * (cosAOI / sin(sunAlt))
    let G_inc = G_horiz * (cosAOI / Math.sin(sunAlt));

    // Limitation physique : G_inc ne peut pas être infinie au lever du soleil
    G_inc = Math.min(G_inc, G_horiz * 1.5); 

    // 5. Vieillissement
    const msPerYear = 1000 * 60 * 60 * 24 * 365.25;
    const ageInYears = Math.max(0, (now - new Date(installDate)) / msPerYear);
    const ageFactor = Math.max(0.7, 1 - (ageInYears * annualDegradation));

    // 6. Correction thermique (NOCT)
    const T_cell = T_ext + (G_inc * (25 / 800)); // (45-20)/800 = 25/800
    const thermalCorrection = 1 + tempCoeff * (T_cell - 25);

    // 7. Calcul Final
    let power = G_inc * efficiency * thermalCorrection * ageFactor;

    return Math.round(Math.max(0, power) * 100) / 100;
}

MoonTrajectory_calc.fnCalc:
/**
 * Calcule la projection de la lune sur un plan vertical face à l'utilisateur (Regard vers le Sud)
 * @param {Object} data - Objet contenant la date (data.d)
 * @param {number} lon - Longitude du lieu
 * @param {number} lat - Latitude du lieu
 * @param {number} alt - Altitude du lieu (en mètres, optionnel pour la réfraction)
 * @returns {Object} Coordonnées Ux, Vy et direction
 */
(data, lon=%longitude%, lat=%latitude% , alt=%altitude%) => {
    // ── 1. Position solaire via SunCalc ──────────────────────────────
    // azimuth  : radians, N=0, sens horaire (E=π/2, S=π, W=3π/2)
    // altitude : radians, élévation au-dessus de l'horizon
    const pos = SunCalc.getMoonPosition(new Date(data.d), lat, lon);

    const az = pos.azimuth;   // [rad]
    const el = pos.altitude;  // [rad]

    // ── 2. Vecteur lune unitaire en repère ENU ────────────────────
    //   S_E = cos(el) · sin(az)   — East
    //   S_N = cos(el) · cos(az)   — North  (profondeur, non utilisée ici)
    //   S_U = sin(el)             — Up

    // ── 3. Projection sur le plan vertical (Est–Up) ──────────────────
    //   Ux : composante horizontale sur le mur  (← W  /  E →)
    //   Vy : composante verticale sur le mur    (↑ Up)
    const Ux = Math.cos(el) * Math.sin(az);   // ∈ [-1, 1]
    const Vy = -Math.sin(el);                  // ∈ [-1, 1]

    // ── 4. Direction azimutale en degrés ─────────────────────────────
    const dir = pos.azimuthDegrees;           // [°]  N=0, E=90, S=180, W=270

    return {
        "d":   data.d,
        "Ux":  Ux,
        "Vy":  Vy,
        "dir": dir,
        "val": pos.distance.toFixed(0) + 'km'
    };
}

