/**
 * Calcule la projection du soleil sur un plan vertical face à l'utilisateur (Regard vers le Sud)
 * @param {Object} data - Objet contenant la date (data.d)
 * @param {number} lon - Longitude du lieu
 * @param {number} lat - Latitude du lieu
 * @param {number} alt - Altitude du lieu (en mètres, optionnel pour la réfraction)
 * @returns {Object} Coordonnées Ux, Vy et direction
 */
(data, lon=%longitude%, lat=%latitude% , alt=%altitude%) => {
    // ── 1. Position solaire via SunCalc ──────────────────────────────
    // azimuth  : radians, N=0, sens horaire (E=π/2, S=π, W=3π/2)
    // altitude : radians, élévation au-dessus de l'horizon
    const pos = SunCalc.getPosition(new Date(data.d), lat, lon);

    const az = pos.azimuth;   // [rad]
    const el = pos.altitude;  // [rad]

    // ── 2. Vecteur solaire unitaire en repère ENU ────────────────────
    //   S_E = cos(el) · sin(az)   — East
    //   S_N = cos(el) · cos(az)   — North  (profondeur, non utilisée ici)
    //   S_U = sin(el)             — Up

    // ── 3. Projection sur le plan vertical (Est–Up) ──────────────────
    //   Ux : composante horizontale sur le mur  (← W  /  E →)
    //   Vy : composante verticale sur le mur    (↑ Up)
    const Ux = Math.cos(el) * Math.sin(az);   // ∈ [-1, 1]
    const Vy = -Math.sin(el);                  // ∈ [-1, 1]

    // ── 4. Direction azimutale en degrés ─────────────────────────────
    const dir = pos.azimuthDegrees;           // [°]  N=0, E=90, S=180, W=270

    return {
        "d":   data.d,
        "Ux":  Ux,
        "Vy":  Vy,
        "dir": dir
    };
}
